// src/utils/spinner.ts
import ora from "ora";
function spinner(text) {
  return ora({
    text,
    spinner: "dots"
  });
}

// src/utils/errors.ts
function handleError(error) {
  if (typeof error === "string") {
    logger.error(error);
    process.exit(1);
  }
  if (error instanceof Error) {
    logger.error(error.message);
    process.exit(1);
  }
  logger.error("Something went wrong. Please try again.");
  process.exit(1);
}

